/// <summary>
/// Extension for the <c>InventDimFieldBinding</c> table in the ETGSPAIN model.
/// </summary>
[ExtensionOf(tableStr(InventDimFieldBinding))]
Final class InventDimFieldBindingETGSPAIN_Extension
{
}

Method.Source:
/// <summary>
/// Provides the field binding for a specific <c>InventDimension</c>.
/// </summary>
/// <param name="_className">The name of the class to bind.</param>
/// <returns>This method is the extension point to provide the specific installation binding.</returns>
protected static FieldName className2FieldName(ClassName _className)
{
    var fieldName = next className2FieldName(_className);

    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        if (_className == classStr(ETGSPAINInventTrackingDimension_Application))
        {
            return fieldStr(InventDim, InventDimension1);
        }
    }
    return fieldName;
}
